#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int a, b, c;
        if (scanf("%d %d %d", &a, &b, &c) != 3) break;
        int result = (b > a + c) && (b % 2 == 1);
        printf("%d\n", result);
    }
    return 0;
}

